// === TOPIC TO URL ===
// If mode=topic, call Claude Haiku to generate an Amazon search URL for the given topic.
// If mode=asins, pass data through unchanged for the next node to handle.

const https = require('https');
const ANTHROPIC_KEY = $env.ANTHROPIC_API_KEY;
if (!ANTHROPIC_KEY) throw new Error('ANTHROPIC_API_KEY not set in n8n environment');

const data = $input.first().json;
const mode = (data['mode'] || 'topic').toLowerCase().trim();
const topic = (data['topic'] || '').trim();
const market = (data['market'] || 'uk').toLowerCase().trim();
const maxResults = Math.max(1, Math.min(50, parseInt(data['max_results'] || '15', 10) || 15));

// Pass-through for asins mode — next node handles ASIN list
if (mode === 'asins') {
  return [{ json: { ...data, mode, market, max_results: maxResults, category_url: null } }];
}

// Topic mode: ask Haiku for an Amazon search URL
if (!topic) throw new Error('The "topic" field is required when mode=topic');

function httpsPost(hostname, path, bodyStr, headers) {
  return new Promise((resolve, reject) => {
    const opts = {
      hostname, port: 443, path, method: 'POST',
      headers: { ...headers, 'Content-Length': Buffer.byteLength(bodyStr) }
    };
    const req = https.request(opts, res => {
      let buf = '';
      res.on('data', c => buf += c);
      res.on('end', () => {
        try { resolve(JSON.parse(buf)); } catch(e) { resolve({ _raw: buf.substring(0, 500) }); }
      });
    });
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}

const prompt = `Given this book topic, generate an Amazon search URL. Use amazon.co.uk for UK market, amazon.com for US market. Return ONLY the URL, nothing else — no explanation, no quotes, no markdown. Topic: ${topic}, Market: ${market}`;

const body = JSON.stringify({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 256,
  messages: [{ role: 'user', content: prompt }]
});

const result = await httpsPost('api.anthropic.com', '/v1/messages', body, {
  'x-api-key': ANTHROPIC_KEY,
  'anthropic-version': '2023-06-01',
  'content-type': 'application/json'
});

const rawUrl = (result?.content?.[0]?.text || '').trim().replace(/^["']|["']$/g, '');

if (!rawUrl || !rawUrl.startsWith('http')) {
  throw new Error(`Haiku returned an unexpected value instead of a URL: ${rawUrl || '(empty)'}`);
}

return [{ json: { ...data, mode, market, max_results: maxResults, topic, category_url: rawUrl } }];

// === SCRAPE CATEGORY & PARSE ASINs ===
// topic/category mode: Firecrawl scrapes the Amazon search results page, then
//   ASIN product links are extracted and limited to max_results.
// asins mode: product URL targets are built directly from the comma-separated 'input' field.

const http = require('http');
const https = require('https');

const FIRECRAWL_KEY = $env.FIRECRAWL_API_KEY;
if (!FIRECRAWL_KEY) throw new Error('FIRECRAWL_API_KEY not set in n8n environment');

const data = $input.first().json;
const mode = (data['mode'] || 'topic').toLowerCase().trim();
const market = (data['market'] || 'uk').toLowerCase().trim();
const maxResults = Math.max(1, Math.min(50, parseInt(data['max_results'] || '15', 10) || 15));
const domain = market === 'us' ? 'www.amazon.com' : 'www.amazon.co.uk';

function post(useHttps, hostname, port, path, bodyStr, headers) {
  return new Promise((resolve, reject) => {
    const lib = useHttps ? https : http;
    const opts = {
      hostname, port, path, method: 'POST',
      headers: { ...headers, 'Content-Length': Buffer.byteLength(bodyStr) }
    };
    const req = lib.request(opts, res => {
      let buf = '';
      res.on('data', c => buf += c);
      res.on('end', () => {
        try { resolve(JSON.parse(buf)); } catch(e) { resolve({ _raw: buf.substring(0, 500) }); }
      });
    });
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}

// ASINS mode: build product URL targets directly from comma-separated ASINs
if (mode === 'asins') {
  const rawInput = data['input'] || '';
  if (!rawInput.trim()) throw new Error('The "input" field (comma-separated ASINs) is required when mode=asins');
  const asins = rawInput.split(',').map(s => s.trim()).filter(Boolean).slice(0, maxResults);
  const targets = asins.map(asin => ({ url: `https://${domain}/dp/${asin}`, asin }));
  return [{ json: { targets, market, count: targets.length, topic: null, category_url: null } }];
}

// Topic mode: scrape the Amazon search results page via Firecrawl Cloud API
const categoryUrl = data['category_url'];
if (!categoryUrl) throw new Error('No category URL was produced by the Topic to URL node');

const scrapeBody = JSON.stringify({ url: categoryUrl, formats: ['markdown'], onlyMainContent: true });
const scrapeResult = await post(true, 'api.firecrawl.dev', 443, '/v1/scrape', scrapeBody, {
  'Authorization': `Bearer ${FIRECRAWL_KEY}`,
  'Content-Type': 'application/json'
});

const markdown = scrapeResult?.data?.markdown || '';
if (!scrapeResult.success || !markdown || markdown.length < 100) {
  throw new Error(`Firecrawl failed to scrape the search results page: ${scrapeResult?.error || 'Empty or blocked response'}. ` +
    'If this keeps failing, configure a residential proxy in Firecrawl (see PR description for DataImpulse setup instructions).');
}

// Extract ASINs from markdown links — Amazon product links contain /dp/ASIN or /gp/product/ASIN
const asinPattern = /\/(?:dp|gp\/product)\/([A-Z0-9]{10})/g;
const seenAsins = new Set();
const targets = [];
let match;
while ((match = asinPattern.exec(markdown)) !== null) {
  const asin = match[1];
  if (!seenAsins.has(asin) && targets.length < maxResults) {
    seenAsins.add(asin);
    targets.push({ url: `https://${domain}/dp/${asin}`, asin });
  }
}

if (targets.length === 0) {
  throw new Error('No ASINs found in the scraped search results page. ' +
    'Amazon may have blocked the request — configure a residential proxy in Firecrawl to fix this (see PR description).');
}

return [{ json: { targets, market, count: targets.length, topic: data['topic'] || null, category_url: categoryUrl } }];

// === SCRAPE & EXTRACT ===
// Receives a targets array [{url, asin}] from the previous node.
// Scrapes each product page via Firecrawl and extracts structured data with Claude Haiku.

const http = require('http');
const https = require('https');

const FIRECRAWL_KEY = $env.FIRECRAWL_API_KEY;
if (!FIRECRAWL_KEY) throw new Error('FIRECRAWL_API_KEY not set in n8n environment');
const ANTHROPIC_KEY = $env.ANTHROPIC_API_KEY;
if (!ANTHROPIC_KEY) throw new Error('ANTHROPIC_API_KEY not set in n8n environment');

const data = $input.first().json;
const targets = data.targets || [];
const market = data.market || 'uk';

const sleep = ms => new Promise(r => setTimeout(r, ms));

function post(useHttps, hostname, port, path, bodyStr, headers) {
  return new Promise((resolve, reject) => {
    const lib = useHttps ? https : http;
    const opts = {
      hostname, port, path, method: 'POST',
      headers: { ...headers, 'Content-Length': Buffer.byteLength(bodyStr) }
    };
    const req = lib.request(opts, res => {
      let buf = '';
      res.on('data', c => buf += c);
      res.on('end', () => {
        try { resolve(JSON.parse(buf)); } catch(e) { resolve({ _raw: buf.substring(0,500) }); }
      });
    });
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}

async function firecrawlScrape(url) {
  try {
    const body = JSON.stringify({ url, formats: ['markdown'] });
    const result = await post(true, 'api.firecrawl.dev', 443, '/v1/scrape', body, {
      'Authorization': `Bearer ${FIRECRAWL_KEY}`,
      'Content-Type': 'application/json'
    });
    const md = result?.data?.markdown || '';
    if (!result.success || !md || md.includes('Continue shopping') || md.length < 200) {
      return { success: false, error: result?.error || 'Blocked or empty (Amazon bot protection)' };
    }
    return { success: true, markdown: md };
  } catch(e) {
    return { success: false, error: e.message };
  }
}

async function extractWithHaiku(url, markdown) {
  const schema = '{"title":null,"subtitle":null,"author":null,"price_current":null,"price_paperback":null,"price_ebook":null,"rating":null,"review_count":null,"bsr_main":null,"bsr_categories":[],"categories":[],"bullets":[],"description":null,"page_count":null,"pub_date":null,"asin":null}';
  const content = `Extract structured product data from this Amazon book listing. Return ONLY valid JSON matching this schema (no markdown fences, no explanation). Schema: ${schema}\n\nURL: ${url}\n\nMarkdown:\n${markdown.substring(0, 8000)}`;
  try {
    const body = JSON.stringify({
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 1024,
      messages: [{ role: 'user', content }]
    });
    const result = await post(true, 'api.anthropic.com', 443, '/v1/messages', body, {
      'x-api-key': ANTHROPIC_KEY,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    });
    const text = result?.content?.[0]?.text || '';
    const cleaned = text.replace(/^```json\s*/m,'').replace(/^```\s*/m,'').replace(/\s*```$/m,'').trim();
    return { success: true, data: JSON.parse(cleaned) };
  } catch(e) {
    return { success: false, data: { extraction_error: e.message } };
  }
}

const listings = [];
for (let i = 0; i < targets.length; i++) {
  const { url, asin } = targets[i];
  const entry = { url, asin };
  const scrapeResult = await firecrawlScrape(url);
  if (i < targets.length - 1) await sleep(2000);
  if (scrapeResult.success) {
    const extraction = await extractWithHaiku(url, scrapeResult.markdown);
    Object.assign(entry, extraction.data);
  } else {
    entry.scrape_error = scrapeResult.error;
  }
  listings.push(entry);
}

return [{ json: { listings, count: listings.length, market, topic: data.topic || null } }];

// === ANALYSE with Claude Sonnet ===
const https = require('https');
const ANTHROPIC_KEY = $env.ANTHROPIC_API_KEY;
if (!ANTHROPIC_KEY) throw new Error('ANTHROPIC_API_KEY not set');

const { listings, count, market, topic } = $input.first().json;

function httpsPost(hostname, path, bodyStr, headers) {
  return new Promise((resolve, reject) => {
    const opts = {
      hostname, port: 443, path, method: 'POST',
      headers: { ...headers, 'Content-Length': Buffer.byteLength(bodyStr) }
    };
    const req = https.request(opts, res => {
      let buf = '';
      res.on('data', c => buf += c);
      res.on('end', () => {
        try { resolve(JSON.parse(buf)); } catch(e) { resolve({ _raw: buf.substring(0, 500) }); }
      });
    });
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}

const allBlocked = count === 0 || listings.every(l => l.scrape_error);
const scrapeNote = allBlocked
  ? '\n\n> **Note:** Amazon scraping was blocked (bot protection). Analysis based on general KDP market knowledge for these listings.'
  : '';

const topicNote = topic ? `\nResearch Topic: ${topic}` : '';

const prompt = `You are a KDP market research analyst. Analyse these Amazon book listings and write a comprehensive Markdown research report.\n\n## 1. Price Positioning\n## 2. Common Keywords & Themes\n## 3. Review Distribution\n## 4. Differentiation Opportunities\n## 5. Recommended Positioning\n## Summary Table\n| Title | Author | Price | Rating | Reviews | BSR |\n|-------|--------|-------|--------|---------|-----|\n\nMarket: ${market}${topicNote}${scrapeNote}\nListings: ${count}\n\nData:\n${JSON.stringify(listings, null, 2).substring(0, 15000)}`;

const body = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  messages: [{ role: 'user', content: prompt }]
});

const result = await httpsPost('api.anthropic.com', '/v1/messages', body, {
  'x-api-key': ANTHROPIC_KEY,
  'anthropic-version': '2023-06-01',
  'content-type': 'application/json'
});

const analysisText = result?.content?.[0]?.text || result?._raw || 'No analysis';
return [{ json: { analysisText, listingCount: count, market, topic: topic || null } }];

const { analysisText, listingCount, market, topic } = $input.first().json;
const now = new Date();
const ts = now.toISOString().replace(/[:.]/g,'-').replace('T','_').slice(0,19);
const topicSlug = topic ? '-' + topic.toLowerCase().replace(/[^a-z0-9]+/g,'-').slice(0,30) : '';
const filename = `report-${ts}${topicSlug}.md`;
const filepath = `/opt/firecrawl/research-cache/${filename}`;

const topicLine = topic ? `**Topic:** ${topic}  \n` : '';
const report = `# Book Market Research Report\n\n**Generated:** ${now.toISOString()}  \n**Market:** ${market}  \n${topicLine}**Listings analysed:** ${listingCount}\n\n---\n\n${analysisText}\n`;

const base64 = Buffer.from(report,'utf-8').toString('base64');
return [{
  json: { filepath, filename, reportLength: report.length },
  binary: {
    report: {
      data: base64,
      mimeType: 'text/markdown',
      fileName: filename,
      fileExtension: 'md'
    }
  }
}];

// Write report to /opt/firecrawl/research-cache/ using fs module
const fs = require('fs');
const path = require('path');

const { filepath, filename, reportLength } = $input.first().json;
const binaryData = $input.first().binary?.report;

if (!binaryData) throw new Error('No binary report data found');

// Decode base64
const content = Buffer.from(binaryData.data, 'base64');

// Ensure directory exists
const dir = path.dirname(filepath);
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

// Write file
fs.writeFileSync(filepath, content);

return [{ json: { filepath, filename, reportLength, written: true } }];
